import 'package:flutter_test/flutter_test.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/ingredient.dart';\n\nvoid main() {\n  group('Ingredient Entity Tests', () {\n    late Ingredient testIngredient;\n    late NutritionInfo testNutrition;\n    late StorageInfo testStorage;\n\n    setUp(() {\n      testNutrition = const NutritionInfo(\n        calories: 364.0,\n        protein: 10.3,\n        carbohydrates: 76.3,\n        fat: 1.9,\n        fiber: 2.7,\n        sugar: 0.3,\n        sodium: 2.0,\n        potassium: 107.0,\n        calcium: 15.0,\n        iron: 1.2,\n      );\n\n      testStorage = const StorageInfo(\n        location: StorageLocation.pantry,\n        temperatureMin: 10,\n        temperatureMax: 25,\n        humidityMin: 30,\n        humidityMax: 60,\n        storageInstructions: ['Store in airtight container', 'Keep in cool, dry place'],\n        requiresRefrigeration: false,\n        lightSensitive: false,\n        airSensitive: true,\n      );\n\n      testIngredient = Ingredient(\n        id: 'flour-001',\n        name: 'All-Purpose Flour',\n        category: 'grains',\n        description: 'Versatile wheat flour for baking and cooking',\n        imageUrl: 'https://example.com/flour.jpg',\n        isOrganic: false,\n        isGlutenFree: false,\n        isVegan: true,\n        isVegetarian: true,\n        isDairyFree: true,\n        isNutFree: true,\n        allergens: ['gluten'],\n        nutritionPer100g: testNutrition,\n        commonUnits: ['cup', 'g', 'kg', 'oz', 'lb'],\n        defaultUnit: 'cup',\n        averagePricePerUnit: 2.50,\n        shelfLifeDays: 365,\n        storageInfo: testStorage,\n        substitutes: ['whole wheat flour', 'cake flour', 'bread flour'],\n        densityGPerMl: 0.6,\n        createdAt: DateTime.now(),\n      );\n    });\n\n    test('should create ingredient with all properties', () {\n      expect(testIngredient.id, 'flour-001');\n      expect(testIngredient.name, 'All-Purpose Flour');\n      expect(testIngredient.category, 'grains');\n      expect(testIngredient.description, 'Versatile wheat flour for baking and cooking');\n      expect(testIngredient.isVegan, true);\n      expect(testIngredient.isGlutenFree, false);\n      expect(testIngredient.allergens, contains('gluten'));\n      expect(testIngredient.commonUnits.length, 5);\n      expect(testIngredient.substitutes.length, 3);\n    });\n\n    test('should have correct default values', () {\n      const minimalIngredient = Ingredient(\n        id: 'ing-001',\n        name: 'Test Ingredient',\n        category: 'other',\n      );\n\n      expect(minimalIngredient.isOrganic, false);\n      expect(minimalIngredient.isGlutenFree, false);\n      expect(minimalIngredient.isVegan, false);\n      expect(minimalIngredient.isVegetarian, false);\n      expect(minimalIngredient.isDairyFree, false);\n      expect(minimalIngredient.isNutFree, false);\n      expect(minimalIngredient.allergens, isEmpty);\n      expect(minimalIngredient.commonUnits, isEmpty);\n      expect(minimalIngredient.averagePricePerUnit, 0.0);\n      expect(minimalIngredient.shelfLifeDays, 0);\n      expect(minimalIngredient.substitutes, isEmpty);\n      expect(minimalIngredient.densityGPerMl, 1.0);\n    });\n\n    test('should serialize to and from JSON correctly', () {\n      final json = testIngredient.toJson();\n      final deserializedIngredient = Ingredient.fromJson(json);\n\n      expect(deserializedIngredient.id, testIngredient.id);\n      expect(deserializedIngredient.name, testIngredient.name);\n      expect(deserializedIngredient.category, testIngredient.category);\n      expect(deserializedIngredient.isVegan, testIngredient.isVegan);\n      expect(deserializedIngredient.allergens, testIngredient.allergens);\n      expect(deserializedIngredient.commonUnits, testIngredient.commonUnits);\n      expect(deserializedIngredient.averagePricePerUnit, testIngredient.averagePricePerUnit);\n    });\n\n    test('should handle copyWith correctly', () {\n      final updatedIngredient = testIngredient.copyWith(\n        name: 'Organic All-Purpose Flour',\n        isOrganic: true,\n        averagePricePerUnit: 3.50,\n      );\n\n      expect(updatedIngredient.name, 'Organic All-Purpose Flour');\n      expect(updatedIngredient.isOrganic, true);\n      expect(updatedIngredient.averagePricePerUnit, 3.50);\n      // Other fields should remain the same\n      expect(updatedIngredient.id, testIngredient.id);\n      expect(updatedIngredient.category, testIngredient.category);\n      expect(updatedIngredient.isVegan, testIngredient.isVegan);\n    });\n\n    test('should handle nutrition information correctly', () {\n      expect(testIngredient.nutritionPer100g?.calories, 364.0);\n      expect(testIngredient.nutritionPer100g?.protein, 10.3);\n      expect(testIngredient.nutritionPer100g?.carbohydrates, 76.3);\n      expect(testIngredient.nutritionPer100g?.fat, 1.9);\n      expect(testIngredient.nutritionPer100g?.fiber, 2.7);\n    });\n\n    test('should handle storage information correctly', () {\n      expect(testIngredient.storageInfo?.location, StorageLocation.pantry);\n      expect(testIngredient.storageInfo?.temperatureMin, 10);\n      expect(testIngredient.storageInfo?.temperatureMax, 25);\n      expect(testIngredient.storageInfo?.requiresRefrigeration, false);\n      expect(testIngredient.storageInfo?.airSensitive, true);\n      expect(testIngredient.storageInfo?.storageInstructions.length, 2);\n    });\n  });\n\n  group('NutritionInfo Tests', () {\n    test('should create nutrition info with default values', () {\n      const nutrition = NutritionInfo();\n\n      expect(nutrition.calories, 0.0);\n      expect(nutrition.protein, 0.0);\n      expect(nutrition.carbohydrates, 0.0);\n      expect(nutrition.fat, 0.0);\n      expect(nutrition.fiber, 0.0);\n      expect(nutrition.sugar, 0.0);\n      expect(nutrition.sodium, 0.0);\n      expect(nutrition.vitaminC, 0.0);\n      expect(nutrition.calcium, 0.0);\n      expect(nutrition.iron, 0.0);\n    });\n\n    test('should serialize nutrition info correctly', () {\n      const nutrition = NutritionInfo(\n        calories: 250.0,\n        protein: 8.0,\n        carbohydrates: 45.0,\n        fat: 5.0,\n        fiber: 3.0,\n        vitaminC: 10.0,\n        calcium: 100.0,\n      );\n\n      final json = nutrition.toJson();\n      final deserialized = NutritionInfo.fromJson(json);\n\n      expect(deserialized.calories, 250.0);\n      expect(deserialized.protein, 8.0);\n      expect(deserialized.carbohydrates, 45.0);\n      expect(deserialized.vitaminC, 10.0);\n      expect(deserialized.calcium, 100.0);\n    });\n\n    test('should handle comprehensive nutrition data', () {\n      const nutrition = NutritionInfo(\n        calories: 364.0,\n        protein: 10.3,\n        carbohydrates: 76.3,\n        fat: 1.9,\n        fiber: 2.7,\n        sugar: 0.3,\n        sodium: 2.0,\n        potassium: 107.0,\n        calcium: 15.0,\n        iron: 1.2,\n        vitaminC: 0.0,\n        vitaminA: 0.0,\n        vitaminD: 0.0,\n        vitaminE: 0.05,\n        vitaminK: 0.3,\n        folate: 20.0,\n        vitaminB12: 0.0,\n        magnesium: 22.0,\n        phosphorus: 108.0,\n        zinc: 0.7,\n      );\n\n      expect(nutrition.calories, 364.0);\n      expect(nutrition.vitaminE, 0.05);\n      expect(nutrition.folate, 20.0);\n      expect(nutrition.magnesium, 22.0);\n      expect(nutrition.zinc, 0.7);\n    });\n  });\n\n  group('StorageInfo Tests', () {\n    test('should create storage info with required fields', () {\n      const storage = StorageInfo(\n        location: StorageLocation.refrigerator,\n      );\n\n      expect(storage.location, StorageLocation.refrigerator);\n      expect(storage.temperatureMin, 0);\n      expect(storage.temperatureMax, 25);\n      expect(storage.humidityMin, 0);\n      expect(storage.humidityMax, 100);\n      expect(storage.requiresRefrigeration, false);\n      expect(storage.requiresFreezing, false);\n      expect(storage.lightSensitive, false);\n      expect(storage.airSensitive, false);\n    });\n\n    test('should serialize storage info correctly', () {\n      const storage = StorageInfo(\n        location: StorageLocation.freezer,\n        temperatureMin: -18,\n        temperatureMax: -10,\n        requiresFreezing: true,\n        lightSensitive: true,\n        storageInstructions: ['Wrap tightly', 'Use within 6 months'],\n      );\n\n      final json = storage.toJson();\n      final deserialized = StorageInfo.fromJson(json);\n\n      expect(deserialized.location, StorageLocation.freezer);\n      expect(deserialized.temperatureMin, -18);\n      expect(deserialized.temperatureMax, -10);\n      expect(deserialized.requiresFreezing, true);\n      expect(deserialized.lightSensitive, true);\n      expect(deserialized.storageInstructions.length, 2);\n    });\n  });\n\n  group('Ingredient Enums Tests', () {\n    test('StorageLocation enum should have all locations', () {\n      expect(StorageLocation.values.length, 6);\n      expect(StorageLocation.values, contains(StorageLocation.pantry));\n      expect(StorageLocation.values, contains(StorageLocation.refrigerator));\n      expect(StorageLocation.values, contains(StorageLocation.freezer));\n      expect(StorageLocation.values, contains(StorageLocation.counter));\n      expect(StorageLocation.values, contains(StorageLocation.cellar));\n      expect(StorageLocation.values, contains(StorageLocation.spiceRack));\n    });\n\n    test('IngredientCategory enum should cover all categories', () {\n      expect(IngredientCategory.values.length, greaterThan(15));\n      expect(IngredientCategory.values, contains(IngredientCategory.vegetables));\n      expect(IngredientCategory.values, contains(IngredientCategory.fruits));\n      expect(IngredientCategory.values, contains(IngredientCategory.proteins));\n      expect(IngredientCategory.values, contains(IngredientCategory.dairy));\n      expect(IngredientCategory.values, contains(IngredientCategory.grains));\n      expect(IngredientCategory.values, contains(IngredientCategory.spices));\n    });\n\n    test('Allergen enum should cover common allergens', () {\n      expect(Allergen.values, contains(Allergen.gluten));\n      expect(Allergen.values, contains(Allergen.dairy));\n      expect(Allergen.values, contains(Allergen.eggs));\n      expect(Allergen.values, contains(Allergen.nuts));\n      expect(Allergen.values, contains(Allergen.peanuts));\n      expect(Allergen.values, contains(Allergen.soy));\n      expect(Allergen.values, contains(Allergen.fish));\n      expect(Allergen.values, contains(Allergen.shellfish));\n    });\n  });\n\n  group('Ingredient Edge Cases', () {\n    test('should handle ingredients with no nutrition info', () {\n      const ingredient = Ingredient(\n        id: 'salt-001',\n        name: 'Table Salt',\n        category: 'condiments',\n      );\n\n      expect(ingredient.nutritionPer100g, isNull);\n      expect(ingredient.storageInfo, isNull);\n    });\n\n    test('should handle ingredients with multiple allergens', () {\n      const ingredient = Ingredient(\n        id: 'bread-001',\n        name: 'Whole Wheat Bread',\n        category: 'grains',\n        allergens: ['gluten', 'soy'],\n        isGlutenFree: false,\n        isVegan: false,\n      );\n\n      expect(ingredient.allergens.length, 2);\n      expect(ingredient.allergens, contains('gluten'));\n      expect(ingredient.allergens, contains('soy'));\n    });\n\n    test('should handle ingredients with extensive substitutes list', () {\n      const ingredient = Ingredient(\n        id: 'butter-001',\n        name: 'Unsalted Butter',\n        category: 'dairy',\n        substitutes: [\n          'margarine',\n          'coconut oil',\n          'vegetable oil',\n          'applesauce',\n          'avocado',\n          'greek yogurt'\n        ],\n      );\n\n      expect(ingredient.substitutes.length, 6);\n      expect(ingredient.substitutes, contains('coconut oil'));\n      expect(ingredient.substitutes, contains('applesauce'));\n    });\n\n    test('should handle perishable vs non-perishable ingredients', () {\n      const perishable = Ingredient(\n        id: 'milk-001',\n        name: 'Whole Milk',\n        category: 'dairy',\n        shelfLifeDays: 7,\n        storageInfo: StorageInfo(\n          location: StorageLocation.refrigerator,\n          requiresRefrigeration: true,\n        ),\n      );\n\n      const nonPerishable = Ingredient(\n        id: 'rice-001',\n        name: 'White Rice',\n        category: 'grains',\n        shelfLifeDays: 1095, // 3 years\n        storageInfo: StorageInfo(\n          location: StorageLocation.pantry,\n          requiresRefrigeration: false,\n        ),\n      );\n\n      expect(perishable.shelfLifeDays, 7);\n      expect(perishable.storageInfo?.requiresRefrigeration, true);\n      expect(nonPerishable.shelfLifeDays, 1095);\n      expect(nonPerishable.storageInfo?.requiresRefrigeration, false);\n    });\n  });\n}\n